html:
{%- set brand_blue = "#1B4F8A" -%}
{%- set brand_teal = "#0E7C7B" -%}
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<style>
* { box-sizing:border-box; margin:0; padding:0; }
body {
font-family: Arial, sans-serif;
font-size: 10px;
color: #222;
background: #fff;
}
/* ── Letterhead ───────────────────────────────────── */
.hdr {
display: flex;
justify-content: space-between;
align-items: flex-start;
padding: 12px 16px 8px;
border-bottom: 3px solid {{ brand_blue }};
margin-bottom: 10px;
}
.clinic-name {
font-size: 15px;
font-weight: bold;
color: {{ brand_blue }};
text-transform: uppercase;
letter-spacing: 0.5px;
}
.clinic-sub {
font-size: 9px;
color: {{ brand_teal }};
text-transform: uppercase;
letter-spacing: 1px;
margin-top: 2px;
}
.rpt-title { text-align: right; }
.rpt-title h2 { font-size: 13px; color: {{ brand_blue }}; font-weight: bold; }
.rpt-title p { font-size: 9px; color: #666; margin-top: 2px; }
/* ── Patient meta grid ────────────────────────────── */
.meta {
display: grid;
grid-template-columns: repeat(4, 1fr);
gap: 4px 12px;
background: #f4f8fc;
border: 1px solid #d0dce8;
border-radius: 4px;
padding: 8px 12px;
margin: 0 16px 10px;
}
.meta-item label {
display: block;
font-size: 8px;
color: #888;
text-transform: uppercase;
letter-spacing: 0.5px;
}
.meta-item span { font-weight: bold; font-size: 9.5px; }
/* ── Section heading ──────────────────────────────── */
.sec {
font-size: 10px;
font-weight: bold;
color: {{ brand_blue }};
text-transform: uppercase;
letter-spacing: 0.5px;
padding: 4px 16px;
border-left: 3px solid {{ brand_teal }};
margin: 8px 16px 4px;
}
/* ── Summary row ─────────────────────────────────── */
.summary {
display: grid;
grid-template-columns: repeat(5, 1fr);
gap: 6px;
padding: 6px 16px 10px;
}
.s-card {
border: 1px solid #d0dce8;
border-radius: 4px;
padding: 6px 8px;
text-align: center;
}
.s-card .val { font-size: 18px; font-weight: bold; color: {{ brand_blue }}; }
.s-card .lbl { font-size: 8px; color: #888; text-transform: uppercase; margin-top: 2px; }
/* ── Legend ──────────────────────────────────────── */
.legend {
display: flex;
gap: 16px;
align-items: center;
padding: 2px 16px 8px;
font-size: 8.5px;
flex-wrap: wrap;
}
.leg-item { display: flex; align-items: center; gap: 4px; }
.swatch { width: 10px; height: 10px; border-radius: 2px; display: inline-block; }
.bop-dot {
display: inline-block;
width: 7px; height: 7px;
border-radius: 50%;
background: #cc0000;
vertical-align: middle;
}
/* ── Perio table ──────────────────────────────────── */
.tbl-wrap { padding: 0 16px; margin-bottom: 12px; }
table.pt {
width: 100%;
border-collapse: collapse;
table-layout: fixed;
}
table.pt thead th {
background: {{ brand_blue }};
color: #fff;
font-size: 9px;
font-weight: bold;
text-align: center;
padding: 5px 3px;
border: 1px solid #2a5f9e;
}
table.pt thead th:first-child {
text-align: left;
padding-left: 6px;
width: 90px;
}
table.pt tbody tr:nth-child(even) { background: #f9fbfd; }
table.pt tbody td {
text-align: center;
padding: 4px 2px;
border: 1px solid #dde5ef;
font-size: 9.5px;
font-weight: bold;
}
table.pt tbody td:first-child {
text-align: left;
padding-left: 6px;
background: #eef2f7;
color: #444;
font-size: 9px;
}
/* ── PD colour classes — Task 40 ─────────────────── */
/* Rule: PD <= 3 → green | PD 4-5 → amber | PD >= 6 → red */
.pd-h { color: #1a7a1a; } /* healthy ≤ 3mm */
.pd-w { color: #FFBF00; } /* warning 4–5mm */
.pd-d { color: #cc0000; } /* disease ≥ 6mm */
.pd-e { color: #ccc; } /* empty / no reading */
/* ── Notes box ───────────────────────────────────── */
.notes {
margin: 0 16px 10px;
border: 1px solid #d0dce8;
border-radius: 4px;
padding: 8px 10px;
font-size: 9.5px;
color: #333;
min-height: 36px;
}
/* ── Footer ──────────────────────────────────────── */
.ftr {
border-top: 1px solid #d0dce8;
padding: 6px 16px;
display: flex;
justify-content: space-between;
font-size: 8px;
color: #999;
margin-top: 8px;
}
@media print {
.tbl-wrap { page-break-inside: avoid; }
}
</style>
</head>
<body>
{# ══ MACRO: resolve PD class
══════════════════════════════════════════════ #}
{%- macro pd_cls(v) -%}
{%- set n = v | int -%}
{%- if n == 0 -%}pd-e
{%- elif n <= 3 -%}pd-h
{%- elif n <= 5 -%}pd-w
{%- else -%}pd-d{%- endif -%}
{%- endmacro -%}
{# ══ MACRO: single PD <td> with optional BOP dot ═════════════════════════
#}
{%- macro pd_td(v, bop) -%}
<td class="{{ pd_cls(v) }}">
{{- v if v else "—" -}}
{%- if bop %}<br><span class="bop-dot"></span>{%- endif %}
</td>
{%- endmacro -%}
{# ══ PRE-CALCULATE summary counters
══════════════════════════════════════ #}
{%- set ns = namespace(sites=0, bop=0, pd4=0, pd6=0, rec=0) -%}
{%- for row in doc.perio_measurements -%}
{%- for i in [1,2,3] -%}
{%- set pd = row["pd_" ~ i] | int -%}
{%- set bop = row["bop_" ~ i] -%}
{%- set gm = row.get("gm_" ~ i, 0) | int -%}
{%- if pd > 0 -%}
{%- set ns.sites = ns.sites + 1 -%}
{%- if pd >= 4 -%}{%- set ns.pd4 = ns.pd4 + 1 -%}{%- endif -%}
{%- if pd >= 6 -%}{%- set ns.pd6 = ns.pd6 + 1 -%}{%- endif -%}
{%- endif -%}
{%- if bop -%}{%- set ns.bop = ns.bop + 1 -%}{%- endif -%}
{%- if gm < 0 -%}{%- set ns.rec = ns.rec + 1 -%}{%- endif -%}
{%- endfor -%}
{%- endfor -%}
{# ══ HEADER
════════════════════════════════════════════════════════════
══ #}
<div class="hdr">
<div>
<div class="clinic-name">Hayat Specialist Hospital, Kano</div>
<div class="clinic-sub">Dental Division — ERPNext Healthcare</div>
</div>
<div class="rpt-title">
<h2>Periodontal Examination</h2>
<p>Confidential — Medical Record</p>
</div>
</div>
{# ══ PATIENT META
══════════════════════════════════════════════════════════ #}
<div class="meta">
<div class="meta-item">
<label>Patient</label>
<span>{{ doc.patient_name or doc.patient }}</span>
</div>
<div class="meta-item">
<label>Patient ID</label>
<span>{{ doc.patient }}</span>
</div>
<div class="meta-item">
<label>Exam Date</label>
<span>{{ frappe.format(doc.exam_date, {"fieldtype":"Date"}) }}</span>
</div>
<div class="meta-item">
<label>Practitioner</label>
<span>{{ doc.practitioner or "—" }}</span>
</div>
<div class="meta-item">
<label>BOP %</label>
<span>{{ "%.1f"|format(doc.bop_percentage) if doc.bop_percentage else "—" }}%</span>
</div>
<div class="meta-item">
<label>Gingival Status</label>
<span>{{ doc.gingival_status or "—" }}</span>
</div>
<div class="meta-item">
<label>Record</label>
<span>{{ doc.name }}</span>
</div>
<div class="meta-item">
<label>Printed</label>
<span>{{ frappe.utils.now_datetime().strftime("%d %b %Y %H:%M") }}</span>
</div>
</div>
{# ══ SUMMARY CARDS
═════════════════════════════════════════════════════════ #}
<div class="summary">
<div class="s-card">
<div class="val">{{ ns.sites }}</div>
<div class="lbl">Sites Recorded</div>
</div>
<div class="s-card">
<div class="val" style="color:#cc0000;">{{ ns.bop }}</div>
<div class="lbl">BOP Sites</div>
</div>
<div class="s-card">
<div class="val" style="color:#FFBF00;">{{ ns.pd4 }}</div>
<div class="lbl">PD ≥ 4mm</div>
</div>
<div class="s-card">
<div class="val" style="color:#cc0000;">{{ ns.pd6 }}</div>
<div class="lbl">PD ≥ 6mm</div>
</div>
<div class="s-card">
<div class="val" style="color:#1B4F8A;">{{ ns.rec }}</div>
<div class="lbl">Recession Sites</div>
</div>
</div>
{# ══ LEGEND
════════════════════════════════════════════════════════════
════ #}
<div class="legend">
<strong>Pocket Depth Key:</strong>
<div class="leg-item">
<span class="swatch" style="background:#1a7a1a;"></span>
<span class="pd-h">≤ 3mm — Healthy</span>
</div>
<div class="leg-item">
<span class="swatch" style="background:#FFBF00;"></span>
<span class="pd-w">4–5mm — Monitor</span>
</div>
<div class="leg-item">
<span class="swatch" style="background:#cc0000;"></span>
<span class="pd-d">≥ 6mm — Disease</span>
</div>
<div class="leg-item">
<span class="bop-dot"></span> Bleeding on Probing
</div>
</div>
{# ══ MEASUREMENTS TABLE
════════════════════════════════════════════════════ #}
{#
6-COLUMN LAYOUT per the spec:
Facial row → MB | B | DB | (lingual cols blank)
Lingual row → (facial cols blank) | ML | L | DL
Columns: Tooth | MB | B | DB | ML | L | DL | Mob. | Furc.
#}
<div class="sec">Probing Depth Measurements</div>
<div class="tbl-wrap">
<table class="pt">
<thead>
<tr>
<th>Tooth / Surface</th>
<th>MB</th>
<th>B</th>
<th>DB</th>
<th>ML</th>
<th>L</th>
<th>DL</th>
<th>Mob.</th>
<th>Furc.</th>
</tr>
</thead>
<tbody>
{%- for row in doc.dental_perio_measurement | sort(attribute="tooth_number") -%}
<tr>
<td>
<strong>{{ row.tooth_number }}</strong>
{%- if row.sequence %}
<span style="color:#999;font-weight:normal;"> {{ row.sequence }}</span>
{%- endif %}
</td>

{%- if row.sequence_type == "Facial" or not row.sequence -%}
{{ pd_td(row.pd_1, row.bop_1) }}
{{ pd_td(row.pd_2, row.bop_2) }}
{{ pd_td(row.pd_3, row.bop_3) }}
<td class="pd-e">—</td>
<td class="pd-e">—</td>
<td class="pd-e">—</td>
{%- else -%}
<td class="pd-e">—</td>
<td class="pd-e">—</td>
<td class="pd-e">—</td>
{{ pd_td(row.pd_1, row.bop_1) }}
{{ pd_td(row.pd_2, row.bop_2) }}
{{ pd_td(row.pd_3, row.bop_3) }}
{%- endif -%}
<td>{{ row.mobility if row.mobility is not none else "—" }}</td>
<td>{{ row.furcation_l if row.furcation is not none else "—" }}</td>
</tr>
{%- else -%}
<tr>
<td colspan="9" style="text-align:center;color:#aaa;padding:14px;">
No measurements recorded for this exam.
</td>
</tr>
{%- endfor -%}
</tbody>
</table>
</div>
{# ══ VISIT NOTES
═══════════════════════════════════════════════════════════
#}
{%- if doc.visit_notes -%}
<div class="sec">Visit Notes</div>
<div class="notes">{{ doc.visit_notes }}</div>
{%- endif -%}
{# ══ FOOTER
════════════════════════════════════════════════════════════
════ #}
<div class="ftr">
<span> Hayat Specialist Hospital, Kano</span>
<span>{{ doc.name }} — Printed {{ frappe.utils.now_datetime().strftime("%d %b %Y %H:%M")
}}</span>
<span>CONFIDENTIAL — Clinical use only</span>
</div>
</body>
</html>
